```typescript
function solve(n: number, edges: number[][], k: number): number {
    let maxTime = 0;
    for (const [u, v, t] of edges) {
        if (t > maxTime) maxTime = t;
    }

    let low = 0, high = maxTime;
    let answer = maxTime;

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const components = countComponents(n, edges, mid);
        if (components >= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}

function countComponents(n: number, edges: number[][], t: number): number {
    const parent = new Array(n).fill(0).map((_, i) => i);
    const rank = new Array(n).fill(0);

    function find(u: number): number {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    function union(u: number, v: number): boolean {
        const rootU = find(u);
        const rootV = find(v);
        if (rootU === rootV) return false;
        if (rank[rootU] > rank[rootV]) {
            parent[rootV] = rootU;
        } else {
            parent[rootU] = rootV;
            if (rank[rootU] === rank[rootV]) {
                rank[rootV] += 1;
            }
        }
        return true;
    }

    for (const [u, v, time] of edges) {
        if (time > t) {
            union(u, v);
        }
    }

    const roots = new Set<number>();
    for (let i = 0; i < n; i++) {
        roots.add(find(i));
    }

    return roots.size;
}
```

